"use client";

import type { Variants } from "motion/react";
import { motion, useAnimation } from "motion/react";
import type { HTMLAttributes } from "react";
import { forwardRef, useCallback, useImperativeHandle, useRef } from "react";

import { cn } from "@/lib/utils";

export interface CupSodaIconHandle {
  startAnimation: () => void;
  stopAnimation: () => void;
}

interface CupSodaIconProps extends HTMLAttributes<HTMLDivElement> {
  size?: number;
}

const STRAW_VARIANTS: Variants = {
  normal: {
    y: 0,
    scaleY: 1,
    transition: {
      duration: 0.25,
      ease: "easeOut",
    },
  },
  animate: {
    y: [0, -2.2, 0.5, 0],
    scaleY: [1, 1.18, 0.97, 1],
    transition: {
      duration: 0.5,
      ease: [0.34, 1.56, 0.64, 1],
      times: [0, 0.35, 0.65, 1],
    },
  },
};

const WAVE_VARIANTS: Variants = {
  normal: {
    y: 0,
    transition: {
      duration: 0.25,
      ease: "easeOut",
    },
  },
  animate: {
    y: [0, -1, 0],
    transition: {
      duration: 1.8,
      repeat: Number.POSITIVE_INFINITY,
      ease: "easeInOut",
    },
  },
};

const BUBBLE_VARIANTS: Variants = {
  normal: { opacity: 0, y: 0, scale: 1 },
  animate: (delay: number) => ({
    opacity: [0, 0.9, 0.4, 0],
    y: [0, -3, -10, -14],
    scale: [1, 1, 0.85, 0.6],
    transition: {
      duration: 1.5,
      ease: "easeIn",
      delay,
      repeat: Number.POSITIVE_INFINITY,
      repeatDelay: 0,
      times: [0, 0.08, 0.7, 1],
    },
  }),
};

const BUBBLES = [
  { delay: 0, left: 22, bottom: 6, size: 4 },
  { delay: 0.35, left: 30, bottom: 8, size: 3 },
  { delay: 0.7, left: 37, bottom: 5, size: 3 },
  { delay: 1.05, left: 26, bottom: 10, size: 4 },
  { delay: 0.55, left: 33, bottom: 7, size: 2 },
] as const;

const CupSodaIcon = forwardRef<CupSodaIconHandle, CupSodaIconProps>(
  ({ onMouseEnter, onMouseLeave, className, size = 28, ...props }, ref) => {
    const controls = useAnimation();
    const isControlledRef = useRef(false);

    useImperativeHandle(ref, () => {
      isControlledRef.current = true;
      return {
        startAnimation: () => controls.start("animate"),
        stopAnimation: () => controls.start("normal"),
      };
    });

    const handleMouseEnter = useCallback(
      (e: React.MouseEvent<HTMLDivElement>) => {
        if (isControlledRef.current) onMouseEnter?.(e);
        else controls.start("animate");
      },
      [controls, onMouseEnter]
    );

    const handleMouseLeave = useCallback(
      (e: React.MouseEvent<HTMLDivElement>) => {
        if (isControlledRef.current) onMouseLeave?.(e);
        else controls.start("normal");
      },
      [controls, onMouseLeave]
    );

    const s = (v: number) => (v / 64) * size;

    return (
      <div
        className={cn("inline-flex cursor-pointer", className)}
        onMouseEnter={handleMouseEnter}
        onMouseLeave={handleMouseLeave}
        {...props}
      >
        <div style={{ position: "relative", width: size, height: size }}>
          <svg
            fill="none"
            height={size}
            stroke="currentColor"
            strokeLinecap="round"
            strokeLinejoin="round"
            strokeWidth="2"
            style={{ position: "absolute", inset: 0, overflow: "visible" }}
            viewBox="0 0 24 24"
            width={size}
            xmlns="http://www.w3.org/2000/svg"
          >
            <path d="m6 8 1.75 12.28a2 2 0 0 0 2 1.72h4.54a2 2 0 0 0 2-1.72L18 8" />
            <path d="M5 8h14" />
            <motion.path
              animate={controls}
              d="M7 15a6.47 6.47 0 0 1 5 0 6.47 6.47 0 0 0 5 0"
              variants={WAVE_VARIANTS}
            />
            <motion.path
              animate={controls}
              d="m12 8 1-6h2"
              style={{
                transformBox: "fill-box",
                originX: "50%",
                originY: "100%",
              }}
              variants={STRAW_VARIANTS}
            />
          </svg>

          {BUBBLES.map((b, i) => (
            <motion.span
              animate={controls}
              custom={b.delay}
              initial="normal"
              key={i}
              style={{
                position: "absolute",
                borderRadius: "9999px",
                backgroundColor: "currentColor",
                pointerEvents: "none",
                width: s(b.size),
                height: s(b.size),
                left: s(b.left),
                bottom: s(b.bottom),
              }}
              variants={BUBBLE_VARIANTS}
            />
          ))}
        </div>
      </div>
    );
  }
);

CupSodaIcon.displayName = "CupSodaIcon";

export { CupSodaIcon };
